class Solution {
public:
    int getMinSwaps(string num, int k) {
        int n = num.length();
        int result = n;
        int swaps = 0;

        for (int i = 1; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (num[i] < num[j]) {
                    result = min(result, num[i] + num[j]);
                    swaps++;
                }
            }
        }

        return swaps;
    }
};
```

